SELECT (SELECT COUNT(*) FROM store_celebrity_private WHERE contract_time IS NOT NULL)                                                                  AS signed_count,
       (SELECT COUNT(*) FROM store_celebrity_private)                                                                                                  AS total_count,
       ROUND((SELECT COUNT(*) FROM store_celebrity_private WHERE contract_time IS NOT NULL) / (SELECT COUNT(*) FROM store_celebrity_private) * 100, 2) AS percentage;

SELECT platform_name, follower_range, COUNT(*) AS total_count,
SUM(CASE WHEN is_top_star = #{item.itemValue} THEN 1 ELSE 0 END) AS "${item.itemText}"
FROM ( SELECT CASE platform_type WHEN 0 THEN 'Instagram' WHEN 1 THEN 'YouTube' WHEN 2 THEN 'TikTok' ELSE 'Other' END AS platform_name, CASE WHEN platform_type = 2 THEN CASE WHEN followers_num >= 10000000 THEN '10M+' WHEN followers_num BETWEEN 1000000 AND 9999999 THEN '1M-10M' WHEN followers_num BETWEEN 500000 AND 999999 THEN '500K-1M' WHEN followers_num BETWEEN 100000 AND 499999 THEN '100K-500K' ELSE '100K以内' END WHEN platform_type IN (0, 1) THEN CASE WHEN followers_num >= 1000000 THEN '1M+' WHEN followers_num BETWEEN 600000 AND 999999 THEN '600K-1M' WHEN followers_num BETWEEN 300000 AND 599999 THEN '300K-600K' WHEN followers_num BETWEEN 100000 AND 299999 THEN '100K-300K' ELSE '10K-100K' END END AS follower_range, is_top_star FROM store_celebrity_private WHERE 1=1
AND platform_type = #{platformType}
AND platform_type IN (0, 1, 2)
) AS sub GROUP BY platform_name, follower_range ORDER BY FIELD(platform_name, 'TikTok', 'YouTube', 'Instagram'), CASE WHEN follower_range LIKE '%+%' THEN 0 WHEN follower_range LIKE '%M%' THEN 1 WHEN follower_range LIKE '%K%' THEN 2 ELSE 3 END, CAST(SUBSTRING_INDEX(follower_range, 'K', 1) AS DECIMAL(10,0)) DESC

SELECT platform_name, cost_range , COUNT(*) AS total_count,
SUM(CASE WHEN is_top_star = #{item.itemValue} THEN 1 ELSE 0 END) AS "${item.itemText}"
FROM ( SELECT CASE platform_type WHEN 0 THEN 'Instagram' WHEN 1 THEN 'YouTube' WHEN 2 THEN 'TikTok' ELSE 'Other' END AS platform_name, CASE WHEN platform_type = 2 THEN CASE WHEN contract_amount BETWEEN 0 AND 200 THEN '0~200$' WHEN contract_amount BETWEEN 200.01 AND 500 THEN '200~500$' WHEN contract_amount BETWEEN 500.01 AND 800 THEN '500~800$' WHEN contract_amount BETWEEN 800.01 AND 1500 THEN '800~1500$' WHEN contract_amount BETWEEN 1500.01 AND 3000 THEN '1500~3000$' ELSE '3000$+' END WHEN platform_type = 1 THEN CASE WHEN contract_amount BETWEEN 0 AND 500 THEN '0~500$' WHEN contract_amount BETWEEN 500.01 AND 1500 THEN '500~1500$' WHEN contract_amount BETWEEN 1500.01 AND 3000 THEN '1500~3000$' WHEN contract_amount BETWEEN 3000.01 AND 8000 THEN '3000~8000$' ELSE '8000$+' END WHEN platform_type = 0 THEN CASE WHEN contract_amount BETWEEN 0 AND 300 THEN '0~300$' WHEN contract_amount BETWEEN 300.01 AND 800 THEN '300~800$' WHEN contract_amount BETWEEN 800.01 AND 3000 THEN '800~3000$' WHEN contract_amount BETWEEN 3000.01 AND 8000 THEN '3000~8000$' ELSE '8000$+' END END AS cost_range, is_top_star FROM store_celebrity_private WHERE 1=1
AND platform_type = #{platformType}
AND platform_type IN (0, 1, 2)
) AS sub GROUP BY platform_name, cost_range ORDER BY FIELD(platform_name, 'TikTok', 'YouTube', 'Instagram'), CASE WHEN cost_range LIKE '%+' THEN 999999999 ELSE CAST(SUBSTRING_INDEX(cost_range, '~', 1) AS DECIMAL(10,2)) END

SELECT CASE COALESCE(c.platform_type, 0) WHEN 0 THEN 'Instagram' WHEN 1 THEN 'YouTube' WHEN 2 THEN 'TikTok' ELSE 'Other' END AS platformName, u.realname AS counselorName, u.id AS counselorId, COUNT(c.id) AS totalSignedCount,
COUNT(CASE WHEN c.is_top_star = #{item.itemValue} THEN c.id END) AS "${item.remark}"
FROM sys_user u LEFT JOIN store_celebrity_private_counselor s ON u.id = s.celebrity_counselor_id
AND s.contract_time >= #{params.contractStartTime}
AND s.contract_time <= #{params.contractEndTime}
LEFT JOIN store_celebrity_private c ON s.celebrity_private_id = c.id
AND c.platform_type = #{params.platformType}
WHERE u.del_flag = '0' AND u.user_type = 4 AND u.is_leave = 0 GROUP BY u.id, u.realname ORDER BY platformName, totalSignedCount DESC

SELECT CASE scp.platform_type WHEN 0 THEN 'Instagram' WHEN 1 THEN 'YouTube' WHEN 2 THEN 'TikTok' ELSE 'Other' END AS platformName, scpc.celebrity_counselor_name AS counselorName, TRIM(SUBSTRING_INDEX(SUBSTRING_INDEX(scp.like_tags, ',', numbers.n), ',', -1)) AS categoryName, CASE scp.is_top_star
WHEN #{item.itemValue} THEN #{item.remark}
END AS starLevel, COUNT(DISTINCT scpc.id) AS count FROM store_celebrity_private scp JOIN store_celebrity_private_counselor scpc ON scp.id = scpc.celebrity_private_id JOIN (SELECT 1 AS n UNION SELECT 2 UNION SELECT 3 UNION SELECT 4 UNION SELECT 5) numbers ON CHAR_LENGTH(scp.like_tags) - CHAR_LENGTH(REPLACE(scp.like_tags, ',', '')) >= numbers.n - 1 WHERE scp.like_tags IS NOT NULL AND scp.like_tags != ''
AND scp.platform_type = #{platformType}
GROUP BY scp.platform_type, scpc.celebrity_counselor_name, TRIM(SUBSTRING_INDEX(SUBSTRING_INDEX(scp.like_tags, ',', numbers.n), ',', -1)), scp.is_top_star ORDER BY platformName, counselorName, starLevel

